import React, { useState } from 'react';
import { BrowserRouter as Router, Routes, Route } from 'react-router-dom';
import './App.css';
import { 
  Header, 
  HeroSection, 
  AboutSection, 
  BlepharoplastySection, 
  StatsSection, 
  ProceduresPage,
  SocialButtons,
  Footer 
} from './components';

const HomePage = () => {
  return (
    <div className="min-h-screen bg-gradient-to-b from-stone-50 to-stone-100">
      <Header />
      <HeroSection />
      <AboutSection />
      <BlepharoplastySection />
      <StatsSection />
      <Footer />
      <SocialButtons />
    </div>
  );
};

const ProceduresPageComponent = () => {
  return (
    <div className="min-h-screen bg-gradient-to-b from-stone-50 to-stone-100">
      <Header />
      <ProceduresPage />
      <Footer />
      <SocialButtons />
    </div>
  );
};

function App() {
  return (
    <Router>
      <div className="App">
        <Routes>
          <Route path="/" element={<HomePage />} />
          <Route path="/procedimentos" element={<ProceduresPageComponent />} />
          <Route path="/sobre" element={<HomePage />} />
          <Route path="/cirurgia-blefaroplastia" element={<HomePage />} />
          <Route path="/resultados" element={<HomePage />} />
          <Route path="/noticias" element={<HomePage />} />
          <Route path="/contato" element={<HomePage />} />
        </Routes>
      </div>
    </Router>
  );
}

export default App;
